+
+        assert_eq!(
+            argz_create_sep(raw, b':' as c_int, &mut argz, &mut argz_len),
+            libc::EINVAL
+        );
+        assert!(argz.is_null());
+        assert_eq!(argz_len, 0);
+
+        assert_eq!(
+            argz_add_sep(&mut argz, &mut argz_len, raw, b':' as c_int),
