+        assert!(argz.is_null());
+        assert_eq!(argz_len, 0);
+
+        assert_eq!(argz_add(&mut argz, &mut argz_len, c"head".as_ptr()), 0);
+        let before = argz;
+        assert_eq!(
+            argz_insert(&mut argz, &mut argz_len, before, raw),
